import{_ as a,o as d,c as i,a2 as e}from"./chunks/framework.BWuWLRhz.js";const s="/assets/cases/liduoxing/sixiangjia-bi/xmind-business-framework.png",r="/assets/cases/liduoxing/sixiangjia-bi/xmind-dashboard-framework.png",u=JSON.parse('{"title":"私享家 BI 数据看板","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/sixiangjia-bi.md","filePath":"projects/liduoxing/sixiangjia-bi.md"}'),n={name:"projects/liduoxing/sixiangjia-bi.md"};function l(o,t,h,p,c,b){return d(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="私享家-bi-数据看板" tabindex="-1">私享家 BI 数据看板 <a class="header-anchor" href="#私享家-bi-数据看板" aria-label="Permalink to &quot;私享家 BI 数据看板&quot;">​</a></h1><blockquote><p>私享家 BI 是围绕金融策略产品搭建的经营分析看板项目。它把 <span class="text-highlight-blue">策略收益、案例股表现、客户价值、产品活跃、客服 / 投顾服务、订单退款和经营结果</span> 放入统一分析框架，帮助管理层和业务团队从“看单点数据”升级到“看策略 - 客户 - 服务 - 收入 - 风险”的完整链路。</p></blockquote><div class="project-snapshot"><div><strong>5 大模块</strong><span>总览、策略收益、客户价值、产品分析、客服投顾服务</span></div><div><strong>P0 优先级</strong><span>策略收益、案例池选股和总览驾驶舱优先建设</span></div><div><strong>多角色使用</strong><span>管理层、投研、运营、客服投顾、数据研发</span></div><div><strong>多周期复盘</strong><span>日、7 天、30 天、90 天、自定义周期</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>私享家业务以股票策略组合、案例池选股、VIP 服务和内容运营为核心。后台已有较多策略与股票相关数据，例如策略组合、批量调仓、案例股池、持仓股票和历史案例股数据。</p><p>但业务真正要回答的问题更复杂：</p><ul><li>哪些策略表现好，是否值得继续主推？</li><li>持仓股票对策略收益贡献如何？</li><li>客户是否活跃，是否存在流失、退款或投诉风险？</li><li>客服和投顾服务是否覆盖到位？</li><li>内容、直播、文章、视频等运营动作是否带来有效使用和成交？</li><li>老板和业务负责人能否快速判断业务增长、风险和问题点？</li></ul><p>这些问题分布在策略、客户、服务、内容、订单和退款多个系统里。如果没有统一 BI，业务只能通过单点报表和经验判断，很难形成持续复盘。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>建立面向管理层和业务团队的 <span class="text-highlight">统一经营驾驶舱</span>。</li><li>优先搭建策略收益和案例池选股分析，支撑产品主推和投研复盘。</li><li>接入客户、订单、退款、活跃和服务数据，形成客户价值分析。</li><li>建立客服 / 投顾服务分析，识别未互动客户、服务覆盖和服务质量问题。</li><li>支持按时间、策略、客户类型、产品权限、服务人员等维度筛选和下钻。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我在项目中负责需求梳理、看板结构设计、指标口径拆解、字段说明和原型 demo 推进。这个项目的重点，是把业务负责人脑中的经营问题转成数据研发可以开发、业务团队可以使用的指标体系。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>场景梳理</td><td>梳理管理层、投研、运营、客服 / 投顾和数据研发的不同关注点</td></tr><tr><td>模块规划</td><td>设计总览驾驶舱、策略收益、客户价值、产品分析、客服投顾服务五大模块</td></tr><tr><td>指标口径</td><td>拆解收益率、盈利策略占比、最大回撤、活跃率、退款率、未互动客户等指标</td></tr><tr><td>交互设计</td><td>设计时间筛选、策略筛选、客户筛选、下钻、排序和导出规则</td></tr><tr><td>数据协同</td><td>和业务、数仓、开发确认数据来源、服务周期、订单退款、企微服务关系等口径</td></tr></tbody></table><h2 id="看板模块" tabindex="-1">看板模块 <a class="header-anchor" href="#看板模块" aria-label="Permalink to &quot;看板模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>主要回答的问题</th><th>核心数据</th></tr></thead><tbody><tr><td>总览驾驶舱</td><td>业务整体增长还是下滑，风险在哪里</td><td>收入、策略表现、用户增长、退款、活跃、服务</td></tr><tr><td>策略收益分析</td><td>哪些策略赚钱，风险是否可控</td><td>策略组合、持仓股票、收益率、回撤、指数对比</td></tr><tr><td>客户价值分析</td><td>客户是否活跃，是否转化、复购、留存</td><td>付费客户、退款客户、在期客户、复购客户、客户状态</td></tr><tr><td>产品分析</td><td>APP、PC、小程序和内容功能是否被使用</td><td>DAU、三端活跃、视频观看、直播互动、页面点击</td></tr><tr><td>客服 / 投顾服务</td><td>服务是否覆盖到位，未互动客户在哪里</td><td>单聊、群发、回复率、服务客户数、未回复客户</td></tr></tbody></table><h2 id="核心指标设计" tabindex="-1">核心指标设计 <a class="header-anchor" href="#核心指标设计" aria-label="Permalink to &quot;核心指标设计&quot;">​</a></h2><p>策略收益是第一阶段 P0 模块。它不仅看单个策略涨跌，还要同时看风险、持仓和商业价值。</p><table tabindex="0"><thead><tr><th>指标类型</th><th>代表指标</th><th>业务价值</th></tr></thead><tbody><tr><td>策略表现</td><td>累计收益率、近 7/30/90 日收益、平均收益率</td><td>判断策略是否值得主推</td></tr><tr><td>风险控制</td><td>最大回撤、回撤区间、波动率、盈利策略占比</td><td>判断收益是否稳定，风险是否可接受</td></tr><tr><td>持仓贡献</td><td>持仓股票收益、涨跌幅、持仓周期、贡献度</td><td>判断策略收益来自哪些股票</td></tr><tr><td>客户价值</td><td>总付费用户、新增付费、退款客户、复购客户、在期客户</td><td>判断客户经营质量</td></tr><tr><td>服务质量</td><td>回复率、通话率、观看率、未互动客户、高质量单聊</td><td>判断服务动作是否影响留存和退款</td></tr></tbody></table><h2 id="业务拆解与指标框架" tabindex="-1">业务拆解与指标框架 <a class="header-anchor" href="#业务拆解与指标框架" aria-label="Permalink to &quot;业务拆解与指标框架&quot;">​</a></h2><p>私享家 BI 的前期难点在于业务链路很长：策略组合、案例股、客户付费、复购退款、内容触达、客服投顾服务都和经营结果相关。我先把业务拆成 <span class="text-highlight">策略组合数据、服务运营数据、客户行为数据、收入与退款数据</span> 几层，再继续拆指标口径和看板模块。</p><h2 id="交付成果" tabindex="-1">交付成果 <a class="header-anchor" href="#交付成果" aria-label="Permalink to &quot;交付成果&quot;">​</a></h2><div class="insight-card"><span class="label">项目结果</span><p>交付私享家 BI 看板，覆盖策略收益、客户价值、APP 产品频道分析、客服投顾服务 4 个模块，接入 APP、小程序、PC、企微 4 端数据。使用方涵盖业务负责人、产品运营主管和客服主管，替代原有手工拉报表方式。因早期数据需经数仓清洗后才可用，项目从启动到上线历时约 1.5 个月。</p></div><div class="case-image-grid"><figure><img src="'+s+'" alt="私享家 BI 业务数据框架 XMind"><figcaption><strong>业务数据框架：先拆业务，再拆指标</strong><span>从策略组合售卖、服务运营、客户行为、收入退款等维度梳理数据层级，明确看板需要追踪经营结果背后的业务动作。</span></figcaption></figure><figure><img src="'+r+`" alt="私享家 BI 看板指标框架 XMind"><figcaption><strong>看板指标框架：把经营问题翻译成可开发模块</strong><span>将业务问题落到总览、策略收益、客户分析、产品分析、客服投顾服务等模块，提前确认每个模块需要看什么、按什么口径统计、如何继续下钻。</span></figcaption></figure></div><h2 id="看板原型交付物" tabindex="-1">看板原型交付物 <a class="header-anchor" href="#看板原型交付物" aria-label="Permalink to &quot;看板原型交付物&quot;">​</a></h2><p>我用 HTML 原型把看板结构、指标层级、筛选项、下钻入口和页面布局先做成可讨论的界面，让业务、数仓和开发可以围绕同一张页面确认口径，减少纯文档沟通里的理解偏差。</p><div class="evidence-callout"><span class="label">关于看板截图</span><p>BI 看板涉及策略收益、客户付费、退款、服务覆盖等敏感业务数据，公开作品集不展示原始截图。以上&quot;看板模块&quot;和&quot;核心指标设计&quot;表格已完整说明各模块结构与指标体系；如需了解原型 demo 和看板细节，欢迎面试时沟通。</p></div><table tabindex="0"><thead><tr><th>交付物</th><th>作用</th><th>展示价值</th></tr></thead><tbody><tr><td>XMind 业务框架</td><td>梳理策略、服务、客户、收入和退款之间的关系</td><td>证明前期业务建模能力</td></tr><tr><td>HTML 看板原型</td><td>将指标体系转成可讨论、可评审的界面</td><td>证明产品原型和可视化表达能力</td></tr><tr><td>PRD / 字段说明</td><td>定义页面逻辑、筛选条件、字段含义和验收范围</td><td>证明需求落地和跨团队协同能力</td></tr><tr><td>SQL 数据集说明</td><td>连接指标口径和数据实现</td><td>证明数据产品具备落地实现链路</td></tr></tbody></table><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><p>私享家 BI 的数据链路可以概括为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>策略产品</span></span>
<span class="line"><span>  -&gt; 用户访问</span></span>
<span class="line"><span>  -&gt; 客户活跃</span></span>
<span class="line"><span>  -&gt; 服务互动</span></span>
<span class="line"><span>  -&gt; 订单 / 退款</span></span>
<span class="line"><span>  -&gt; 经营结果</span></span></code></pre></div><p>这条链路让业务可以追问结果背后的原因。例如：某个策略退款率升高，需要同时看策略收益、客户活跃、服务互动、内容触达和客户状态，避免只看退款总数。</p><h2 id="数据难点" tabindex="-1">数据难点 <a class="header-anchor" href="#数据难点" aria-label="Permalink to &quot;数据难点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>难点</th><th>表现</th><th>处理思路</th></tr></thead><tbody><tr><td>服务周期口径复杂</td><td>近 3 天、近 7 天、近 30 天客户是否完整在期会影响分母</td><td>明确统计周期内客户是否需要完整覆盖服务期</td></tr><tr><td>服务关系来源不一</td><td>企微客户管理、公司客户管理、派工关系可能不一致</td><td>根据业务场景选择主口径，并保留差异说明</td></tr><tr><td>群发和单聊区分</td><td>系统群发、手动群发、真实单聊混在一起会影响服务质量判断</td><td>将服务触达拆成不同类型，单独统计</td></tr><tr><td>策略收益快照</td><td>未取关持仓和历史收益需要每日快照才能计算</td><td>对收益、回撤、持仓周期建立时间序列口径</td></tr><tr><td>跨端行为</td><td>APP、小程序、PC 行为需要统一用户标识</td><td>与埋点治理和 ID 映射项目联动</td></tr></tbody></table><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>形成私享家 BI 的模块框架、PRD、字段口径和 demo 原型。</li><li>将业务分析从策略单点收益扩展到客户、服务、内容、订单和退款的闭环。</li><li>建立管理层和业务团队都能理解的经营驾驶舱结构。</li><li>推动业务、数仓、开发围绕统一指标口径协作，减少“同一指标多种说法”的问题。</li><li>为后续用户标签、埋点治理和客户生命周期分析提供承接场景。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目体现的是 <span class="text-highlight-warm">金融策略产品的数据经营能力</span>。我需要同时理解投研策略、客户服务、产品活跃、订单退款和管理层复盘方式，把它们组织成一套可开发、可验收、可持续迭代的 BI 体系。</p>`,37)])])}const x=a(n,[["render",l]]);export{u as __pageData,x as default};
